update modules set focus_items = '[{"prompt": "Define why your business exists.", "guidance": "This isn''t your product description \u2014 it''s the reason behind it. Ask yourself: what bothered you enough that you wanted to fix it? If this business disappeared tomorrow, what would actually be lost?", "placeholder": "e.g. I started this because..."}, {"prompt": "Create a compelling vision and mission.", "guidance": "A vision is where you''re headed \u2014 the future you''re trying to create, even years out. A mission is what you do every day to get there. Keep both short enough to say out loud without checking your notes.", "placeholder": "Vision: In a few years, we... / Mission: We help [who] do [what] by [how]."}, {"prompt": "Identify the problem you''re solving.", "guidance": "Be specific. \"People need better coffee\" is vague. \"Commuters here have nowhere decent to get coffee before their 7am train\" is a problem you can actually solve. Name who has this problem and how painful it really is for them.", "placeholder": "The problem is... and it affects [who] because..."}, {"prompt": "Establish your long-term direction.", "guidance": "This is your multi-year bet \u2014 not a rigid plan, but a direction that helps you say no to the wrong opportunities. What does this business look like when it''s working, and what are you deliberately not trying to be?", "placeholder": "In a few years, this business will..."}]'::jsonb where title = 'Vision & Purpose';
